// B+ Tree 結構示意

// 假設每頁 16KB，key 為 8 bytes，指針 6 bytes
// 每頁可以存儲約 1170 個 key

// 3層 B+ Tree 可以存儲：
// 層1: 1170 個指針 -> 1170 * 1170 = 1,368,900 個 key
// 層2: 1170 個 key
// 層3: 1170 個 key + 數據

// 假設每行數據 200 bytes，每頁 80 行
// 3層: 1170 * 1170 * 80 = 109,512,000 行 = 1億+

// 範圍查詢示例
SELECT * FROM users WHERE age BETWEEN 20 AND 30;

// B+ Tree:
// 1. 定位到 age = 20 既葉節點
// 2. 通過雙向鏈表順序讀取
// 3. 直到 age > 30

// 如果用 B Tree:
// 1. 需要每層都回歸
// 2. 每次都要隨機磁盤讀取
// 3. 效率低好多

