public class Base62Encoder {
    private static final String ALPHABET = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";

    // 將分佈式 ID (10進制) 轉換為短網址 (62進制)
    public static String encode(long num) {
        StringBuilder sb = new StringBuilder();
        while (num > 0) {
            sb.append(ALPHABET.charAt((int) (num % 62)));
            num /= 62;
        }
        return sb.reverse().toString();
    }
}

public boolean isAllowed(String userId) {
    long now = System.currentTimeMillis();
    long windowStart = now - 60000;
    String key = "rate_limit:" + userId;

    // 使用 Pipeline 執行多條 Redis 命令
    Pipeline pipe = jedis.pipelined();
    pipe.zremrangeByScore(key, 0, windowStart); // 清除過期數據
    Response<Long> count = pipe.zcard(key);      // 計算當前窗口請求數
    pipe.sync();

    if (count.get() < 100) {
        jedis.zadd(key, now, UUID.randomUUID().toString());
        return true;
    }
    return false;
}

