PriorityQueue<Order> bids = new PriorityQueue<>(
    (o1, o2) -> o1.price != o2.price ? 
                Double.compare(o2.price, o1.price) : // 買單價格降序 (Max-Heap)
                Long.compare(o1.timestamp, o2.timestamp) // 價格相同則時間升序
);
PriorityQueue<Order> asks = new PriorityQueue<>(
    (o1, o2) -> o1.price != o2.price ? 
                Double.compare(o1.price, o2.price) : // 賣單價格升序 (Min-Heap)
                Long.compare(o1.timestamp, o2.timestamp)
);

public void match() {
    while(!bids.isEmpty() && !asks.isEmpty() && bids.peek().price >= asks.peek().price) {
        Order bid = bids.poll();
        Order ask = asks.poll();
