// 預計元素 100億，可接受誤判率 0.01%
BloomFilter<CharSequence> filter = BloomFilter.create(
    Funnels.stringFunnel(Charset.forName("UTF-8")),
    10_000_000_000L,
    0.0001
);
if (!filter.mightContain(url)) {
    filter.put(url);
    crawl(url);
}

// Spring Batch 核心 Chunk 處理流
@Bean
public Step etlStep() {
    return stepBuilderFactory.get("etlStep")
        .<InternalPosition, AladdinPosition>chunk(1000) // 每次處理 1000 條
        .reader(jdbcCursorItemReader())                 // 流式讀取不撐爆內存
        .processor(positionMappingProcessor())          // 執行複雜字段映射
        .writer(externalApiWriter())                    // 批量上報 API
        .faultTolerant()                                // 容錯配置
        .retryLimit(3).retry(HttpConnectException.class)
        .build();
}

