// 二倍均值法核心邏輯
public List<Integer> splitRedPacket(int totalAmount, int totalPeople) {
    List<Integer> list = new ArrayList<>();
    int restAmount = totalAmount;
    int restPeople = totalPeople;
    Random random = new Random();
    for (int i = 0; i < totalPeople - 1; i++) {
        // 每次隨機範圍：1分錢 到 剩餘平均值的2倍
        int max = (restAmount / restPeople) * 2 - 1;
        int amount = random.nextInt(max) + 1;
        list.add(amount);
        restAmount -= amount;
        restPeople--;
    }
    list.add(restAmount); // 最後一個人拿剩下的
    return list;
}

